const payload = $json && typeof $json === 'object' ? $json : {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

const body = payload.body && typeof payload.body === 'object' ? payload.body : null;
if (body) {
  const message = body.message && typeof body.message === 'object' ? body.message : {};
  const space = body.space && typeof body.space === 'object' ? body.space : (message.space || {});
  const thread = message.thread && typeof message.thread === 'object' ? message.thread : (body.thread || {});
  const threadName = toText(thread.name || '');
  const threadKey = threadName ? threadName.split('/').pop() : toText(message.name || body.messageId || body.eventTime || 'google-chat-thread');

  let commandText = toText(message.argumentText || message.slashCommand?.commandName || message.text || '');
  commandText = commandText.replace(/<users\/[^>]+>/g, ' ').trim();

  const spaceId = toText(space.name || '');
  const sessionId = `${spaceId || 'google-chat'}:${threadKey || 'thread'}`;

  return {
    triggerSource: 'chat',
    channel: 'googleChat',
    commandText,
    actorId: toText(body.user?.name || message.sender?.name || ''),
    actorDisplayName: toText(body.user?.displayName || message.sender?.displayName || ''),
    spaceId,
    threadKey,
    sessionId,
  };
}

const localCommandText = toText(payload.chatInput || payload.text || payload.message?.text || '');
if (localCommandText || payload.userId || payload.sessionId || payload.threadKey || payload.thread) {
  const actorId = toText(payload.actorId || payload.userId || payload.user?.id || 'n8n-chat-user');
  const actorDisplayName = toText(payload.actorDisplayName || payload.userName || payload.user?.name || 'N8N Chat User');
  const rawSpaceId = toText(payload.spaceId || '');
  const rawThreadKey = toText(payload.threadKey || payload.thread || '');
  const rawSessionId = toText(payload.sessionId || '');
  const spaceId = rawSpaceId || 'n8n-chat';
  const threadKey = rawThreadKey || rawSessionId || 'local-chat-thread';
  const sessionId = rawSessionId || `${spaceId}:${threadKey}`;

  return {
    triggerSource: 'chat',
    channel: 'n8nChatTrigger',
    commandText: localCommandText || 'status sprint',
    actorId,
    actorDisplayName,
    spaceId,
    threadKey,
    sessionId,
  };
}

return {
  triggerSource: 'manual',
  channel: 'manualTrigger',
  commandText: 'status sprint',
  actorId: 'manual-trigger',
  actorDisplayName: 'Manual Trigger',
  spaceId: 'manual-trigger-space',
  threadKey: 'manual-jira-ai-agent',
  sessionId: 'manual-trigger-space:manual-jira-ai-agent',
};

const config = {
  jiraBaseUrl: 'https://atlassiansuite.mservice.com.vn:8443',
  jiraApiVersion: '2',
  timeZone: 'Asia/Ho_Chi_Minh',
  ggChatWebhookUrl: 'https://chat.googleapis.com/v1/spaces/AAQAcu_P8pI/messages?key=AIzaSyDdI0hCZtE6vySjMm-WEfRq3CPzqKqqsHI&token=hi3fzzGkR1ri4uotTO2hoa08WxQjdbJbNHPHSJ1S71o',
  googleChatReplyOption: 'REPLY_MESSAGE_FALLBACK_TO_NEW_THREAD',
  defaultLanguage: 'vi',
  writeMode: 'inline-safe-writes',
  nowIso: $now.setZone('Asia/Ho_Chi_Minh').toISO(),
  project: "EXPENSE",
  boardId: 1922
};

return { ...($json || {}), config };

const event = $('Config Main').first().json || {};
const config = event.config || {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  if (typeof value === 'object') return JSON.stringify(value);
  return String(value).trim();
}

const deliveryDefaults = event.channel === 'system' ? ['pushGoogleChat'] : ['reply'];
const context = {
  actor: {
    id: toText(event.actorId || ''),
    displayName: toText(event.actorDisplayName || event.actorId || 'Unknown'),
  },
  channel: toText(event.channel || 'manualTrigger'),
  threadKey: toText(event.threadKey || `thread-${toText(config.nowIso || '')}`),
  sessionId: toText(event.sessionId || ''),
  messageText: toText(event.commandText || ''),
  toolPolicy: {
    preferredTool: 'Jira Tool',
    writeMode: toText(config.writeMode || 'read-only'),
  },
  deliveryDefaults,
  safeConfig: {
    jiraBaseUrl: toText(config.jiraBaseUrl || ''),
    jiraApiVersion: toText(config.jiraApiVersion || '2'),
    jiraCoreApiBaseUrl: toText(config.jiraBaseUrl || '') + '/rest/api/2',
    jiraAgileApiBaseUrl: toText(config.jiraBaseUrl || '') + '/rest/agile/1.0',
    timeZone: toText(config.timeZone || 'Asia/Ho_Chi_Minh'),
    defaultLanguage: toText(config.defaultLanguage || 'vi'),
    nowIso: toText(config.nowIso || ''),
    project: toText(config.project || ''),
    boardId: toText(config.boardId || ''),
  },
};

const chatInput = [
  'Standalone Jira AI Agent request',
  'Return language: Vietnamese unless the user clearly asks otherwise.',
  'No persistent state is available in this phase. Use only short memory window if present.',
  'Context JSON:',
  JSON.stringify(context, null, 2),
].join('\n');

return { ...context, chatInput };

const event = $('Config Main').first().json || {};
const config = event.config || {};
const agent = $json && typeof $json === 'object' ? $json : {};
const parsed = agent.output && typeof agent.output === 'object'
  ? agent.output
  : (agent && typeof agent === 'object' ? agent : {});
const legacyPlan = parsed.deliveryPlan && typeof parsed.deliveryPlan === 'object' ? parsed.deliveryPlan : {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  if (typeof value === 'object') return JSON.stringify(value);
  return String(value).trim();
}

function defaultIntent(commandText) {
  const normalized = toText(commandText).toLowerCase();
  if (/(^|\b)(hello|hi|alo|chào|xin chào|cảm ơn|thanks|thank you)(\b|$)/i.test(normalized)) return 'social';
  if (/(comment|transition|assign|update|edit|release|close|create|delete|approve|reject)/i.test(normalized)) return 'action';
  if (/(analyze|đánh giá|phan tich|phân tích|recommend|de xuat|đề xuất|why|tại sao)/i.test(normalized)) return 'analyze';
  return 'read';
}

function defaultDestinationForChannel(channel) {
  const preferred = toText(channel) === 'system' ? 'pushGoogleChat' : 'reply';
  if (preferred === 'pushGoogleChat' && !toText(config.ggChatWebhookUrl || '')) return 'reply';
  return preferred;
}

function normalizeDestination(rawDestination, fallbackDestination) {
  const type = toText(rawDestination && typeof rawDestination === 'object' ? (rawDestination.destination || rawDestination.type) : rawDestination);
  if (type === 'reply') return 'reply';
  if (type === 'pushGoogleChat') {
    return toText(config.ggChatWebhookUrl || '') ? 'pushGoogleChat' : 'reply';
  }
  return fallbackDestination;
}

function hasNonEmptyValue(value) {
  if (Array.isArray(value)) return value.some((item) => hasNonEmptyValue(item));
  if (value && typeof value === 'object') return Object.values(value).some((item) => hasNonEmptyValue(item));
  return toText(value) !== '';
}

function hasNonEmptyPayload(payload) {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return false;
  const keys = Object.keys(payload);
  if (keys.length === 0) return false;
  return keys.some((key) => hasNonEmptyValue(payload[key]));
}

function buildFallbackTextPayload(message, fallbackText) {
  const text = toText(message?.text || fallbackText);
  return text ? { text } : null;
}

function normalizeMessage(message, fallbackText, fallbackDestination) {
  if (!message || typeof message !== 'object') return null;

  const rawPayload = message.payload && typeof message.payload === 'object' && !Array.isArray(message.payload)
    ? message.payload
    : null;
  const payload = hasNonEmptyPayload(rawPayload) ? rawPayload : buildFallbackTextPayload(message, fallbackText);
  if (!payload) return null;

  const destinationCandidate = message.destination
    || message.destinationType
    || (Array.isArray(message.destinations) ? message.destinations[0] : '')
    || '';
  const destination = normalizeDestination(destinationCandidate, fallbackDestination);

  return {
    destination,
    payload,
  };
}

function normalizeThread(rawThread) {
  const thread = rawThread && typeof rawThread === 'object' ? { ...rawThread } : {};
  if (!toText(thread.threadKey)) {
    thread.threadKey = toText(event.threadKey || '');
  }
  return thread;
}

function normalizeMessages(rawMessages, fallbackText) {
  const fallbackDestination = defaultDestinationForChannel(event.channel || 'manualTrigger');
  const messages = Array.isArray(rawMessages)
    ? rawMessages.map((message) => normalizeMessage(message, fallbackText, fallbackDestination)).filter(Boolean)
    : [];

  if (messages.length === 0) {
    messages.push({
      destination: fallbackDestination,
      payload: { text: fallbackText },
    });
  }

  return messages;
}

function normalizeMeta(rawMeta, fallbackIntent) {
  const allowedIntents = new Set(['read', 'analyze', 'action', 'social']);
  const allowedConfidence = new Set(['low', 'medium', 'high']);
  const intent = allowedIntents.has(toText(rawMeta?.intent)) ? toText(rawMeta.intent) : fallbackIntent;
  const confidence = allowedConfidence.has(toText(rawMeta?.confidence)) ? toText(rawMeta.confidence) : (intent === 'social' ? 'high' : 'medium');
  const usedTools = Array.isArray(rawMeta?.usedTools)
    ? rawMeta.usedTools.map((toolName) => toText(toolName)).filter(Boolean)
    : [];

  return { intent, usedTools, confidence };
}

const fallbackIntent = defaultIntent(event.commandText || '');
let resultText = toText(parsed.resultText || '');

if (!resultText) {
  resultText = fallbackIntent === 'social'
    ? 'Mình đây. Nếu cần tra cứu Jira hoặc phân tích sprint thì nói mình biết nhé.'
    : 'AI Agent không trả đúng structured output như yêu cầu, nên mình chưa thể xác nhận thao tác Jira vừa rồi.';
}

if (fallbackIntent === 'action' && !toText(parsed.resultText || '')) {
  resultText = 'Mình chưa thể xác nhận Jira write đã thực thi vì AI Agent không trả về kết quả chuẩn sau khi hành động.';
}

const meta = normalizeMeta(parsed.meta || {}, fallbackIntent);
const thread = normalizeThread(parsed.thread || legacyPlan.thread || {});
const messages = normalizeMessages(parsed.messages || legacyPlan.messages || [], resultText);

return { toolName: 'jiraAgent', resultText, thread, messages, meta };

const envelope = $('Normalize Agent Result').first().json || {};

function asText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function normalizeEmail(value) {
  const email = asText(value).toLowerCase();
  return email.includes('@') ? email : '';
}

function extractHandleFromEmail(value) {
  const email = normalizeEmail(value);
  return email ? email.split('@')[0] : '';
}

function tokenDisplayText(token) {
  const upper = asText(token).replace(/^@/, '').toUpperCase();
  if (upper === 'LEAD') return '@Lead';
  if (upper === 'PM') return '@PM';
  if (upper === 'ASSIGNEE') return '@ASSIGNEE';
  if (upper === 'OWNER') return '@OWNER';
  if (upper === 'QCS') return '@QCS';
  return '@' + asText(token).replace(/^@/, '');
}

const memberRows = $input.all().map((item) => item?.json || {});
const directoryByKey = new Map();

function registerDirectoryKey(rawKey, entry) {
  const key = asText(rawKey).replace(/^@/, '').toLowerCase();
  if (!key || directoryByKey.has(key)) return;
  directoryByKey.set(key, entry);
}

for (const row of memberRows) {
  const normalized = {};
  for (const [key, value] of Object.entries(row || {})) {
    normalized[String(key || '').trim().toLowerCase()] = value;
  }

  const email = normalizeEmail(normalized.email);
  const id = asText(normalized.id);
  const name = asText(normalized.name || normalized.display_name || normalized.displayname);
  const handle = asText(normalized.handle || normalized.username || normalized.user_name || normalized.jira_username) || extractHandleFromEmail(email);
  if (!id || !email) continue;

  const entry = {
    id,
    email,
    name,
    handle: asText(handle).replace(/^@/, '').toLowerCase(),
    mentionText: '<users/' + id + '>',
  };

  registerDirectoryKey(email, entry);
  registerDirectoryKey(entry.handle, entry);
  registerDirectoryKey(name, entry);
  registerDirectoryKey(normalized.username, entry);
  registerDirectoryKey(normalized.user_name, entry);
  registerDirectoryKey(normalized.jira_username, entry);
  registerDirectoryKey(normalized.display_name, entry);
  registerDirectoryKey(normalized.displayname, entry);
}

function resolveMemberFromToken(token) {
  const key = asText(token).replace(/^@/, '').toLowerCase();
  if (!key) return null;
  return directoryByKey.get(key) || null;
}

function buildMentionFooter(occurrences) {
  const uniqueByMention = new Map();
  for (const occurrence of occurrences.sort((left, right) => left.offset - right.offset)) {
    if (!occurrence?.mentionText || uniqueByMention.has(occurrence.mentionText)) continue;
    uniqueByMention.set(occurrence.mentionText, occurrence);
  }

  const ordered = Array.from(uniqueByMention.values());
  return {
    mentionTail: ordered.map((item) => item.mentionText).join(' '),
    resolvedPeople: ordered.map((item, index) => ({
      token: item.token,
      handle: item.handle,
      mentionText: item.mentionText,
      displayName: item.displayName,
      firstOffset: item.offset,
      order: index,
    })),
    appendedMentionIds: ordered.map((item) => item.mentionText),
  };
}

function renderTextMentions(rawText) {
  const mentionOccurrences = [];
  const roleTokens = [];

  const renderedText = asText(rawText).replace(/(^|[\s(/])\*?@([A-Za-z0-9._-]{2,64})\*?\b/g, (full, prefix, rawToken, offset) => {
    const token = asText(rawToken);
    const upper = token.toUpperCase();
    if (!token) return full;

    if (['PM', 'LEAD', 'ASSIGNEE', 'OWNER', 'QCS'].includes(upper)) {
      roleTokens.push({ token: '@' + upper, offset });
      return prefix + '*' + tokenDisplayText(token) + '*';
    }

    const member = resolveMemberFromToken(token);
    if (member?.mentionText) {
      const handle = asText(member.handle || token).replace(/^@/, '').toLowerCase();
      mentionOccurrences.push({
        token: '@' + token,
        handle,
        mentionText: member.mentionText,
        displayName: asText(member.name || member.email || handle),
        offset,
      });
      return prefix + '*@' + handle + '*';
    }

    return prefix + '*@' + token + '*';
  });

  const footer = buildMentionFooter(mentionOccurrences);
  const finalText = footer.mentionTail ? renderedText + '\\n' + footer.mentionTail : renderedText;

  return {
    text: finalText,
    mentionTail: footer.mentionTail,
    resolvedPeople: footer.resolvedPeople,
    roleTokens: roleTokens.sort((left, right) => left.offset - right.offset).map((item) => item.token),
    appendedMentionIds: footer.appendedMentionIds,
  };
}

const messages = asArray(envelope.messages).map((message, index) => {
  const payload = message?.payload && typeof message.payload === 'object' ? { ...message.payload } : null;
  const rendered = payload && typeof payload.text === 'string'
    ? renderTextMentions(payload.text)
    : null;

  return {
    ...message,
    payload: rendered ? { ...payload, text: rendered.text } : payload,
    mentionRender: rendered ? {
      messageIndex: index,
      destination: asText(message.destination || 'reply'),
      mentionTail: rendered.mentionTail,
      resolvedPeople: rendered.resolvedPeople,
      roleTokens: rendered.roleTokens,
      appendedMentionIds: rendered.appendedMentionIds,
    } : {
      messageIndex: index,
      destination: asText(message.destination || 'reply'),
      mentionTail: '',
      resolvedPeople: [],
      roleTokens: [],
      appendedMentionIds: [],
    },
  };
});

const renderedResult = renderTextMentions(envelope.resultText || '');

return {
  ...envelope,
  resultText: renderedResult.text,
  mentionTail: renderedResult.mentionTail,
  lineMentions: messages.map((message) => message.mentionRender),
  messages: messages.map((message) => {
    const clone = { ...message };
    delete clone.mentionRender;
    return clone;
  }),
};

const envelope = $('Render Mentioned Messages').first().json || {};
const messages = Array.isArray(envelope.messages) ? envelope.messages : [];

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function hasNonEmptyPayload(payload) {
  return payload && typeof payload === 'object' && !Array.isArray(payload) && Object.keys(payload).length > 0;
}

const replyMessages = messages.filter((message) => toText(message?.destination) === 'reply' && hasNonEmptyPayload(message?.payload));
const preferredPayload = replyMessages.find((message) => typeof message.payload?.text === 'string' && message.payload.text.trim())?.payload || replyMessages[0]?.payload || null;

return preferredPayload || { text: toText(envelope.resultText || 'Đã nhận yêu cầu.') };

